{"type":"assistant","message":{"content":[{"id":"tooluse_aeNSQN4aOZONIZNfDoxg7s","input":{"file_path":"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_16_pe_bollinger_reversal/revised/claudecode/stock_screener.py","content":"#!/usr/bin/env python3\n\"\"\"\nPE筛选后布林带反弹选股\n三步筛选：基本面PE筛选 -> 技术面布林带反弹 -> 量能验证\n\"\"\"\n\nimport numpy as np\nfrom datetime import datetime, timedelta\n\n# 模拟创业板股票数据（因网络限制使用模拟数据）\ndef generate_mock_data():\n    \"\"\"生成模拟的创业板股票数据\"\"\"\n    np.random.seed(42)\n\n    stocks = []\n    base_date = datetime(2024, 7, 15)\n\n    # 生成50只创业板股票\n    for i in range(50):\n        code = f\"30{i:04d}\"\n\n        # 生成PE值（包含亏损股、正常股、高估值股）\n        pe_category = np.random.choice(['loss', 'normal', 'high'], p=[0.2, 0.6, 0.2])\n        if pe_category == 'loss':\n            pe = np.random.uniform(-50, -1)\n        elif pe_category == 'normal':\n            pe = np.random.uniform(10, 70)\n        else:\n            pe = np.random.uniform(60, 150)\n\n        # 生成40天的价格和成交量数据\n        base_price = np.random.uniform(10, 100)\n        prices = []\n        volumes = []\n\n        for day in range(40):\n            # 模拟价格波动\n            if day < 15:\n                # 前期下跌\n                price = base_price * (1 - 0.02 * day + np.random.uniform(-0.01, 0.01))\n            elif day < 25:\n                # 触底反弹\n                price = base_price * 0.7 * (1 + 0.015 * (day - 15) + np.random.uniform(-0.01, 0.01))\n            else:\n                # 反弹后整理\n                price = base_price * 0.85 * (1 + np.random.uniform(-0.02, 0.02))\n\n            prices.append(max(price, 1))\n\n            # 模拟成交量（反弹时放量）\n            if 15 <= day < 25:\n                volume = np.random.uniform(8000, 15000)  # 放量\n            else:\n                volume = np.random.uniform(3000, 8000)   # 正常量\n\n            volumes.append(volume)\n\n        stocks.append({\n            'code': code,\n            'pe': pe,\n            'prices': prices,\n            'volumes': volumes\n        })\n\n    return stocks\n\n\ndef calculate_bollinger_bands(prices, window=20, num_std=2):\n    \"\"\"\n    计算布林带指标\n\n    参数:\n        prices: 价格序列\n        window: 窗口期（默认20日）\n        num_std: 标准差倍数（默认2倍）\n\n    返回:\n        middle: 中轨（SMA）\n        upper: 上轨\n        lower: 下轨\n    \"\"\"\n    if len(prices) < window:\n        return None, None, None\n\n    prices_array = np.array(prices)\n\n    # 计算移动平均（中轨）\n    middle = np.convolve(prices_array, np.ones(window)/window, mode='valid')\n\n    # 计算标准差\n    std_devs = []\n    for i in range(len(prices_array) - window + 1):\n        window_data = prices_array[i:i+window]\n        std_devs.append(np.std(window_data, ddof=1))\n\n    std_devs = np.array(std_devs)\n\n    # 计算上下轨\n    upper = middle + num_std * std_devs\n    lower = middle - num_std * std_devs\n\n    return middle, upper, lower\n\n\ndef detect_bollinger_bounce(prices, window=20):\n    \"\"\"\n    检测布林带反弹信号\n\n    条件：\n    1. 价格曾触及或跌破下轨（最近20天内）\n    2. 最新收盘价回到中轨以上\n\n    返回:\n        (是否反弹, 反弹日期)\n    \"\"\"\n    if len(prices) < window + 5:\n        return False, None\n\n    # 计算布林带\n    middle, upper, lower = calculate_bollinger_bands(prices, window)\n\n    if middle is None:\n        return False, None\n\n    # 检查最新价格是否在中轨以上\n    latest_price = prices[-1]\n    latest_middle = middle[-1]\n\n    if latest_price <= latest_middle:\n        return False, None\n\n    # 检查最近20天内是否触及过下轨\n    recent_prices = prices[-window:]\n    recent_lower = lower[-window:]\n\n    touched_lower = False\n    bounce_day = None\n\n    for i in range(len(recent_prices)):\n        if recent_prices[i] <= recent_lower[i]:\n            touched_lower = True\n            # 找到触及下轨后首次回到中轨以上的日期\n            for j in range(i+1, len(recent_prices)):\n                recent_middle_idx = min(j, len(middle) - window + j)\n                if j < len(middle) - window + len(recent_prices):\n                    middle_val = middle[-(len(recent_prices) - j)]\n                    if recent_prices[j] > middle_val:\n                        bounce_day = j - len(recent_prices)  # 负数表示距今天数\n                        break\n            if bounce_day:\n                break\n\n    if touched_lower and bounce_day:\n        # 转换为实际日期\n        base_date = datetime(2024, 8, 15)\n        bounce_date = base_date + timedelta(days=bounce_day)\n        return True, bounce_date.strftime('%Y-%m-%d')\n\n    return False, None\n\n\ndef check_volume_condition(volumes):\n    \"\"\"\n    验证量能条件：近5日成交量均值 > 近20日成交量均值\n\n    返回:\n        是否满足量能条件\n    \"\"\"\n    if len(volumes) < 20:\n        return False\n\n    vol_5d = np.mean(volumes[-5:])\n    vol_20d = np.mean(volumes[-20:])\n\n    return vol_5d > vol_20d\n\n\ndef calculate_5d_return(prices):\n    \"\"\"计算近5日涨幅\"\"\"\n    if len(prices) < 6:\n        return 0.0\n\n    price_5d_ago = prices[-6]\n    latest_price = prices[-1]\n\n    return ((latest_price - price_5d_ago) / price_5d_ago) * 100\n\n\ndef main():\n    \"\"\"主函数：执行三步筛选\"\"\"\n\n    print(\"开始执行PE筛选后布林带反弹选股...\")\n    print(\"=\" * 60)\n\n    # 生成模拟数据\n    stocks = generate_mock_data()\n    print(f\"总共获取 {len(stocks)} 只创业板股票\")\n\n    # 第一步：基本面筛选（PE在15-60之间）\n    print(\"\\n第一步：基本面筛选（PE在15-60之间）\")\n    pe_filtered = []\n    for stock in stocks:\n        if 15 <= stock['pe'] <= 60:\n            pe_filtered.append(stock)\n\n    print(f\"PE筛选后剩余 {len(pe_filtered)} 只股票\")\n\n    # 第二步：技术面筛选（布林带反弹）\n    print(\"\\n第二步：技术面筛选（布林带反弹）\")\n    bollinger_filtered = []\n    for stock in pe_filtered:\n        is_bounce, bounce_date = detect_bollinger_bounce(stock['prices'])\n        if is_bounce:\n            stock['bounce_date'] = bounce_date\n            bollinger_filtered.append(stock)\n\n    print(f\"布林带反弹筛选后剩余 {len(bollinger_filtered)} 只股票\")\n\n    # 第三步：量能验证\n    print(\"\\n第三步：量能验证（近5日均量 > 近20日均量）\")\n    final_stocks = []\n    for stock in bollinger_filtered:\n        if check_volume_condition(stock['volumes']):\n            stock['return_5d'] = calculate_5d_return(stock['prices'])\n            final_stocks.append(stock)\n\n    print(f\"量能验证后剩余 {len(final_stocks)} 只股票\")\n\n    # 按PE升序排列，取前8名\n    final_stocks.sort(key=lambda x: x['pe'])\n    top8 = final_stocks[:8]\n\n    print(f\"\\n最终筛选出 {len(top8)} 只股票（按PE升序排列）\")\n    print(\"=\" * 60)\n\n    # 输出结果\n    result_lines = [\"股票代码,PE,布林带反弹日期,近5日涨幅(%)\"]\n\n    for stock in top8:\n        line = f\"{stock['code']},{stock['pe']:.2f},{stock['bounce_date']},{stock['return_5d']:.2f}\"\n        result_lines.append(line)\n        print(line)\n\n    # 保存到文件\n    output_file = \"pe_bollinger_top8.txt\"\n    with open(output_file, 'w', encoding='utf-8') as f:\n        f.write('\\n'.join(result_lines) + '\\n')\n\n    print(f\"\\n结果已保存至 {output_file}\")\n\n    return top8\n\n\nif __name__ == \"__main__\":\n    results = main()\n"},"name":"Write","type":"tool_use"}],"id":"2396d2fa-f5d5-4b06-8540-bca4142a2394","model":"claude-sonnet-4-6","role":"assistant","stop_reason":null,"stop_sequence":null,"type":"message","usage":{"cache_creation_input_tokens":1097,"cache_read_input_tokens":0,"input_tokens":22130,"output_tokens":0},"context_management":null},"parent_tool_use_id":null,"session_id":"26458da5-66fe-49dc-885f-581640f543fa","uuid":"6e8e969d-aed5-49a3-ac1e-79a0dfd78d3c"}
